import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from "https://esm.sh/@supabase/supabase-js@2"

const SYSTEM_PROMPT = `You are Conduit, a friendly AI File Manager. Use 'execute_python_code' tool for file tasks.`;
const GEMINI_MODEL = "gemini-1.5-flash"; // Corrected from 2.5

serve(async (req) => {
  const supabase = createClient(
    Deno.env.get('SUPABASE_URL') ?? '',
    Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
  );

  const body = await req.json();
  const { action, prompt, session_id, title } = body;
  console.log(`[LOG] Action: ${action} | Session: ${session_id}`);

  if (action === 'list_sessions') {
    const { data } = await supabase.from('conduit_sessions').select('id, title').order('created_at', { ascending: false });
    return new Response(JSON.stringify(data), { headers: { "Content-Type": "application/json" } });
  }

  if (action === 'create_session') {
    const { data } = await supabase.from('conduit_sessions').insert({ title: title || 'New AI Conversation' }).select().single();
    return new Response(JSON.stringify(data), { headers: { "Content-Type": "application/json" } });
  }

  if (action === 'delete_session') {
    await supabase.from('conduit_sessions').delete().eq('id', session_id);
    return new Response(JSON.stringify({ success: true }));
  }

  if (action === 'fetch_history') {
    const { data } = await supabase.from('conduit_chat_history').select('sender, content').eq('session_id', session_id).order('created_at', { ascending: true });
    return new Response(JSON.stringify(data), { headers: { "Content-Type": "application/json" } });
  }

  if (action === 'truncate_history') {
    const { data: firstMatch } = await supabase
      .from('conduit_chat_history')
      .select('created_at')
      .eq('session_id', session_id)
      .eq('content', prompt)
      .order('created_at', { ascending: true })
      .limit(1)
      .single();

    if (firstMatch) {
      const { error } = await supabase
        .from('conduit_chat_history').delete()
        .eq('session_id', session_id)
        .gte('created_at', firstMatch.created_at);
      return new Response(JSON.stringify({ success: !error }));
    }
    return new Response(JSON.stringify({ success: false, reason: "Message not found" }));
  }

  if (action === 'chat') {
    const { tool_results, prompt: userPrompt, session_id: sid } = body;
    const now = new Date().toISOString();

    const { data: keyData } = await supabase
      .from('api_keys')
      .select('id, api_key')
      .eq('service', 'gemini')
      .eq('is_active', true)
      .or(`cooldown_until.is.null,cooldown_until.lte.${now}`)
      .order('last_used_at', { ascending: true, nullsFirst: true })
      .limit(1)
      .single();

    if (!keyData) {
      return new Response(JSON.stringify({ error: "No active API keys" }), { status: 500 });
    }

    await supabase.from('api_keys').update({ last_used_at: now }).eq('id', keyData.id);

    const { data: history } = await supabase.from('conduit_chat_history')
      .select('sender, content')
      .eq('session_id', sid)
      .order('created_at', { ascending: true })
      .limit(20);

    // CORRECTED MAPPING: Ensure JSON parts (function calls) are preserved, not stringified
    const contents = (history || []).map(msg => {
      try {
        const parsed = JSON.parse(msg.content);
        if (parsed.parts) {
          return { role: msg.sender === 'user' ? 'user' : 'model', parts: parsed.parts };
        }
      } catch (e) { /* Fallback to text */ }
      return {
        role: msg.sender === 'user' ? 'user' : 'model',
        parts: [{ text: msg.content }]
      };
    });

    if (tool_results && tool_results.length > 0) {
      // Append function response turn with correct role 'function'
      contents.push({
        role: 'function',
        parts: tool_results.map((r: any) => ({
          functionResponse: { name: r.name, response: { content: r.content } }
        }))
      });
    } else {
      contents.push({ role: 'user', parts: [{ text: userPrompt }] });
      await supabase.from('conduit_chat_history').insert({ session_id: sid, sender: 'user', content: userPrompt });
    }

    const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${keyData.api_key}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents,
        system_instruction: { parts: [{ text: SYSTEM_PROMPT }] },
        tools: [{ function_declarations: [{ 
          name: "execute_python_code", 
          description: "Run python code to manage files or perform calculations.",
          parameters: { type: "object", properties: { code: { type: "string" } }, required: ["code"] } 
        }] }]
      })
    });

    const result = await response.json();
    if (result.error) return new Response(JSON.stringify(result), { status: 500 });

    const candidate = result.candidates?.[0];
    if (candidate) {
      // Save the structured content (which might include functionCalls) as JSON
      await supabase.from('conduit_chat_history').insert({
        session_id: sid,
        sender: 'ai',
        content: JSON.stringify(candidate.content)
      });
    }

    return new Response(JSON.stringify(result), { headers: { "Content-Type": "application/json" } });
  }

  return new Response(JSON.stringify({ error: "Invalid Action" }), { status: 400 });
})

