import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp

@Composable
fun ExplorerScreen() {
    var isSearching by remember { mutableStateOf(false) }
    var searchQuery by remember { mutableStateOf("") }
    var showInternalStorage by remember { mutableStateOf(false) }

    Box(modifier = Modifier.fillMaxSize()) {
        Column(modifier = Modifier.fillMaxSize().padding(horizontal = 20.dp)) {
            // Header with Expanding Search
            Row(
                modifier = Modifier.fillMaxWidth().padding(top = 20.dp, bottom = 10.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                if (!isSearching) {
                    Text("Nexus Explorer", style = MaterialTheme.typography.headlineSmall, fontWeight = FontWeight.Bold)
                }

                ExpandingSearch(
                    isExpanded = isSearching,
                    query = searchQuery,
                    onQueryChange = { searchQuery = it },
                    onToggle = { isSearching = !isSearching }
                )
            }

            LazyColumn(modifier = Modifier.fillMaxSize()) {
                item { Spacer(modifier = Modifier.height(15.dp)) }

                // Storage Card
                item {
                    StorageUsageCard(onClick = { showInternalStorage = true })
                }

                item { Spacer(modifier = Modifier.height(25.dp)) }

                // Category Grid
                item {
                    CategoryGrid()
                }

                item { Spacer(modifier = Modifier.height(30.dp)) }

                // Recent Files Section
                item {
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                        Text("Recent Files", style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.SemiBold)
                        Text("View All", color = Color(0xFF00E5FF), style = MaterialTheme.typography.labelLarge)
                    }
                    Spacer(modifier = Modifier.height(15.dp))
                }

                val dummyFiles = listOf(
                    FileItem("Project_Proposal.pdf", "2.4 MB • 15 mins ago", Icons.Default.Description, Color(0xFFFF5252)),
                    FileItem("main.py", "14 KB • 1 hour ago", Icons.Default.Code, Color(0xFF00E5FF)),
                    FileItem("IMG_20240308.jpg", "4.1 MB • 3 hours ago", Icons.Default.Image, Color(0xFF7C4DFF))
                )

                items(dummyFiles) {
                    FileRow(it)
                    Spacer(modifier = Modifier.height(12.dp))
                }

                item { Spacer(modifier = Modifier.height(100.dp)) }
            }
        }

        // Full Explorer Overlay (Simulating navigation)
        AnimatedVisibility(
            visible = showInternalStorage,
            enter = slideInHorizontally(initialOffsetX = { it }),
            exit = slideOutHorizontally(targetOffsetX = { it })
        ) {
            Surface(modifier = Modifier.fillMaxSize(), color = Color(0xFF0D1117)) {
                Column(modifier = Modifier.fillMaxSize()) {
                    Row(
                        modifier = Modifier.fillMaxWidth().background(Color(0xFF161B22)).padding(top = 50.dp, start = 10.dp, bottom = 10.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        IconButton(onClick = { showInternalStorage = false }) {
                            Icon(Icons.Default.ChevronLeft, null, tint = Color.White)
                        }
                        Text("Internal Storage", color = Color.Gray, fontSize = 14.sp)
                        Icon(Icons.Default.ChevronRight, null, modifier = Modifier.size(14.dp), tint = Color.Gray)
                        Text(" Documents", color = Color(0xFF00E5FF), fontWeight = FontWeight.Bold, fontSize = 14.sp)
                    }

                    // Placeholder for actual file listing
                    Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                        Text("Folder View Coming Soon", color = Color.Gray)
                    }
                }
            }
        }
    }
}

@Composable
fun StorageUsageCard(onClick: () -> Unit) {
    Surface(
        modifier = Modifier.fillMaxWidth().clickable { onClick() },
        shape = RoundedCornerShape(24.dp),
        color = Color.Transparent,
        border = androidx.compose.foundation.BorderStroke(1.dp, Color.White.copy(alpha = 0.1f))
    ) {
        Box(modifier = Modifier.background(Brush.linearGradient(listOf(Color(0xFF1F2937), Color(0xFF111827)))).padding(24.dp)) {
            Column {
                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                    Column {
                        Text("Used Space", color = Color.Gray, fontSize = 12.sp)
                        Text("124.5 GB / 256 GB", color = Color(0xFF00E5FF), fontWeight = FontWeight.Bold, fontSize = 18.sp)
                    }
                    Icon(Icons.Default.Memory, null, tint = Color(0xFF00E5FF))
                }
                Spacer(modifier = Modifier.height(15.dp))
                Box(modifier = Modifier.fillMaxWidth().height(8.dp).background(Color(0xFF0D1117), CircleShape)) {
                    Box(modifier = Modifier.fillMaxWidth(0.65f).fillMaxHeight().background(Color(0xFF00E5FF), CircleShape))
                }
            }
        }
    }
}

@Composable
fun CategoryGrid() {
    val cats = listOf(
        Cat("Images", Icons.Default.Image, Color(0xFFFF5252)),
        Cat("Videos", Icons.Default.Videocam, Color(0xFF7C4DFF)),
        Cat("Audio", Icons.Default.MusicNote, Color(0xFF00E5FF)),
        Cat("Docs", Icons.Default.Description, Color(0xFFFFD740)),
        Cat("Downloads", Icons.Default.Download, Color(0xFF69F0AE)),
        Cat("Zips", Icons.Default.Archive, Color(0xFFFF4081))
    )

    Column {
        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceEvenly) {
            cats.take(3).forEach { CategoryItem(it) }
        }
        Spacer(modifier = Modifier.height(20.dp))
        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceEvenly) {
            cats.takeLast(3).forEach { CategoryItem(it) }
        }
    }
}

@Composable
fun CategoryItem(cat: Cat) {
    Column(horizontalAlignment = Alignment.CenterHorizontally) {
        Box(
            modifier = Modifier.size(55.dp).border(1.dp, Color.White.copy(alpha = 0.1f), RoundedCornerShape(18.dp)).background(Color.White.copy(alpha = 0.05f), RoundedCornerShape(18.dp)),
            contentAlignment = Alignment.Center
        ) {
            Icon(cat.icon, null, tint = cat.color, modifier = Modifier.size(24.dp))
        }
        Spacer(modifier = Modifier.height(8.dp))
        Text(cat.name, color = Color.Gray, fontSize = 12.sp)
    }
}

@Composable
fun ExpandingSearch(isExpanded: Boolean, query: String, onQueryChange: (String) -> Unit, onToggle: () -> Unit) {
    val width by animateDpAsState(targetValue = if (isExpanded) 220.dp else 45.dp, animationSpec = spring(stiffness = Spring.StiffnessLow))

    Surface(
        modifier = Modifier.width(width).height(45.dp),
        shape = RoundedCornerShape(22.dp),
        color = if (isExpanded) Color(0xFF00E5FF).copy(alpha = 0.1f) else Color.White.copy(alpha = 0.05f),
        border = androidx.compose.foundation.BorderStroke(1.dp, if (isExpanded) Color(0xFF00E5FF) else Color.Transparent)
    ) {
        Row(verticalAlignment = Alignment.CenterVertically, modifier = Modifier.padding(horizontal = 12.dp)) {
            Icon(
                Icons.Default.Search, 
                null, 
                tint = Color(0xFF00E5FF), 
                modifier = Modifier.size(20.dp).clickable { onToggle() }
            )
            if (isExpanded) {
                BasicTextField(
                    value = query,
                    onValueChange = onQueryChange,
                    modifier = Modifier.padding(start = 10.dp).weight(1f),
                    textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 14.sp),
                    singleLine = true
                )
            }
        }
    }
}

@Composable
fun FileRow(file: FileItem) {
    Row(
        modifier = Modifier.fillMaxWidth().background(Color.White.copy(alpha = 0.05f), RoundedCornerShape(16.dp)).padding(12.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Icon(file.icon, null, tint = file.color, modifier = Modifier.size(24.dp))
        Spacer(modifier = Modifier.width(15.dp))
        Column {
            Text(file.name, color = Color.White, fontSize = 14.sp)
            Text(file.meta, color = Color.Gray, fontSize = 11.sp)
        }
    }
}

// Helper Models
data class Cat(val name: String, val icon: ImageVector, val color: Color)
data class FileItem(val name: String, val meta: String, val icon: ImageVector, val color: Color)

@Composable
fun BasicTextField(value: String, onValueChange: (String) -> Unit, modifier: Modifier, textStyle: androidx.compose.ui.text.TextStyle, singleLine: Boolean) {
    androidx.compose.foundation.text.BasicTextField(value = value, onValueChange = onValueChange, modifier = modifier, textStyle = textStyle, singleLine = singleLine)
}

